import anthropic
from pathlib import Path

SYSTEM_PROMPT = """
You are a file management assistant. You may only operate on files
within the /workspace directory.

## Tool Use Guardrails
- ONLY operate on files within /workspace. Refuse any request involving
  paths outside /workspace, including paths with '../' traversal.
- Always read a file with read_file before any write or delete operation,
  unless the user explicitly waives the preview.
- NEVER delete a file without first reading it and asking for explicit
  confirmation. Only delete after the user replies 'yes' or 'confirm'.
- Do not create, modify, or delete files matching *.env, *.key, *.pem,
  or *.secret. If asked, say these file types are restricted.

## Scope
File management tasks within /workspace only. Do not perform web searches
or provide general coding tutorials.

## Behavior
Before executing any write, summarize what will be written and to which
file. Confirm with the user before proceeding.
"""

TOOLS = [
    {
        "name": "read_file",
        "description": "Read the contents of a file within /workspace.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Absolute path within /workspace"}
            },
            "required": ["path"]
        }
    },
    {
        "name": "write_file",
        "description": "Write content to a file within /workspace.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "content": {"type": "string"}
            },
            "required": ["path", "content"]
        }
    },
    {
        "name": "delete_file",
        "description": "Delete a file within /workspace after explicit user confirmation.",
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string"}},
            "required": ["path"]
        }
    }
]


def execute_tool(tool_name: str, tool_input: dict) -> str:
    """Application-layer enforcement — validates path even if prompt guardrail bypassed."""
    path = tool_input.get("path", "")
    # Hard enforcement: never bypass this with a prompt
    if not path.startswith("/workspace"):
        return f"Error: Access denied. Path '{path}' is outside /workspace."
    # Block sensitive file patterns at the code level too
    if any(path.endswith(ext) for ext in (".env", ".key", ".pem", ".secret")):
        return f"Error: File type is restricted."
    if tool_name == "read_file":
        p = Path(path)
        return p.read_text() if p.exists() else f"Error: {path} not found."
    if tool_name == "write_file":
        Path(path).parent.mkdir(parents=True, exist_ok=True)
        Path(path).write_text(tool_input["content"])
        return f"Written {len(tool_input['content'])} bytes to {path}."
    if tool_name == "delete_file":
        Path(path).unlink(missing_ok=True)
        return f"Deleted {path}."
    return "Unknown tool."


def run_agent(user_message: str) -> str:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=1024,
            system=SYSTEM_PROMPT,
            tools=TOOLS,
            messages=messages
        )
        if response.stop_reason == "end_turn":
            text_blocks = [b.text for b in response.content if b.type == "text"]
            return " ".join(text_blocks)
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = execute_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})
